using System.Text.Json; using Exam.Core; namespace Exam.Data; public sealed class AgentRepository{readonly string path; public AgentRepository(string? b=null){path=Path.Combine(b??AppContext.BaseDirectory,"resources","seed-agents.json");} public List<Agent> Load()=>File.Exists(path)?JsonSerializer.Deserialize<List<Agent>>(File.ReadAllText(path))??new():new(); public void Save(IEnumerable<Agent> x){Directory.CreateDirectory(Path.GetDirectoryName(path)!);File.WriteAllText(path,JsonSerializer.Serialize(x,new JsonSerializerOptions{WriteIndented=true}));} public bool CanDelete(Agent x)=>!x.HasProductSale;}
